 * (and incrementing by 2) into local maxima, assuming all non-peak neighbors remain at original values.
 * 
 * This approach assumes that to minimize cost for a fixed set of target peaks S, 
 * non-peak neighbors j must remain at original value nums[j], as any increase in nums[j] 
 * would only increase the cost without helping satisfy constraints for other peaks 
 * (since neighbors of peaks are never peaks in the optimal maximal configuration).
 * 
 * @param {number[]} nums The input array.
 * @param {number} start The starting index (1 or 2).
 * @returns {{cost: number, count: number}} An object containing the total cost and the number of peaks achieved.
 */
function calculateCostAndCount(nums, start) {
    const N = nums.length;
    let cost = 0;
    let count = 0;

    // Indices must be in the range [1, N-2]
    // We iterate over the potential peak indices i = start, start + 2, start + 4, ...
    for (let i = start; i <= N - 2; i += 2) {
        // i is a peak candidate

        // Required height H_i must be strictly greater than both neighbors.
        // H_i = max(nums[i-1], nums[i+1]) + 1
        const H_i = Math.max(nums[i - 1], nums[i + 1]) + 1;

        // The target value B_i must be at least nums[i] and at least H_i.
        // B_i = max(nums[i], H_i)
        const B_i = Math.max(nums[i], H_i);

        // Cost contribution: B_i - nums[i]
        cost += B_i - nums[i];
        count++;
    }

    return { cost: cost, count: count };
}

