 * Solves the problem by finding the maximal achievable number of special indices 
 * (K_max) and then finding the configuration that achieves K_max with minimum cost.
 * @param {number[]} nums The input integer array.
 * @returns {number} The minimum total operation cost.
 */
function solve(nums) {
    const N = nums.length;

    // Minimum length for any special index to exist is 3.
    if (N < 3) {
        return 0;
    }

    // We must maximize the count first. The maximum count K_max is floor((N-1)/2).
    // The optimal configuration S must be a sequence of separated indices: {s, s+2, s+4, ...}

    // Test starting at 1 (S1)
    const result1 = calculateCostAndCount(nums, 1);

    let minCost = result1.cost;
    let maxCount = result1.count;

    // Test starting at 2 (S2), only possible if N >= 4
    if (N >= 4) {
        const result2 = calculateCostAndCount(nums, 2);

        if (result2.count > maxCount) {
            // S2 achieves a strictly higher count
            maxCount = result2.count;
            minCost = result2.cost;
        } else if (result2.count === maxCount) {
            // S2 achieves the same maximal count, minimize cost
            minCost = Math.min(minCost, result2.cost);
        }
        // If result2.count < maxCount, we stick with result1's settings.
    }

    return minCost;
}

